#[test]
fn test_convo_history_roundtrip() {
    let convo = StorageRef {
        platform: "gcs".to_string(),
        path: "my-bucket/sessions/conv-001.jsonl".to_string(),
        key_ref: "GCS_CREDS".to_string(),
    };

    let payload = ethabi::encode(&[
        Token::Address(EthAddress::from_slice(Address::repeat_byte(0x02).as_slice())),
        Token::Array(vec![]),
        Token::Uint(EthU256::from(60u64)),
        Token::Array(vec![]),
        Token::Bytes(vec![]),
        Token::String(r#"[{"role":"user","content":"Hi"}]"#.to_string()),
        Token::String("gpt-4o".to_string()),

        ])
    }

    #[test]
    fn test_valid_llm_request() {
        let payload = create_llm_request_payload(
            Address::repeat_byte(0x01),
            30,
            "gpt-4o-mini",
            r#"[{"role":"user","content":"Hello"}]"#,
        );
        let request = LLMCallRequest::from_abi(&payload).unwrap();

        assert_eq!(request.executor, Address::repeat_byte(0x01));
        assert_eq!(request.ttl, 30);
        assert_eq!(request.model, "gpt-4o-mini");
        assert!(request.has_valid_messages());
    }

